query:
{
  connectors(
    where: {
      conditionalAccessPolicies_NONE: {
        conditions: {
          includeUsers_INCLUDES: "All"
          includeApplications_INCLUDES: "All"
          clientAppTypes_INCLUDES: "all"
          NOT: { includeLocations: { eq: [] } }
        }
        grantControls: { builtInControls_INCLUDES: "block" }
      }
    }
  ) {
    ...AssetFragment
  }
}
